<script lang="ts">
  let { platform, url, title }: { platform: string; url: string; title: string } = $props();

  function getShareUrl() {
    const encodedUrl = encodeURIComponent(url);
    const encodedTitle = encodeURIComponent(title);
    switch (platform) {
      case 'reddit': return `https://www.reddit.com/submit?url=${encodedUrl}&title=${encodedTitle}`;
      case 'facebook': return `https://www.facebook.com/sharer/sharer.php?u=${encodedUrl}`;
      case 'pinterest': return `https://pinterest.com/pin/create/button/?url=${encodedUrl}&description=${encodedTitle}`;
      case 'telegram': return `https://t.me/share/url?url=${encodedUrl}&text=${encodedTitle}`;
      case 'whatsapp': return `https://api.whatsapp.com/send?text=${encodedTitle}%20${encodedUrl}`;
      case 'tumblr': return `https://www.tumblr.com/widgets/share/tool?canonicalUrl=${encodedUrl}&title=${encodedTitle}`;
      case 'linkedin': return `https://www.linkedin.com/shareArticle?mini=true&url=${encodedUrl}&title=${encodedTitle}`;
      case 'mix': return `https://mix.com/add?url=${encodedUrl}`;
      case 'twitter': return `https://twitter.com/intent/tweet?text=${encodedTitle}&url=${encodedUrl}`;
      case 'threads': return `https://threads.net/intent/post?text=${encodeURIComponent(title + ' ' + url)}`;
      default: return '#';
    }
  }

  let platformName = $derived(platform === 'twitter' ? 'X' : platform.charAt(0).toUpperCase() + platform.slice(1));
  let shareLink = $derived(getShareUrl());
</script>

